import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { Form, Button, Container } from 'react-bootstrap';
import API_URL from '../config';

function AddEmployee() {
  const [name, setName] = useState('');
  const [position, setPosition] = useState('');
  const [department, setDepartment] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/employees`, { name, position, department }, {
        headers: { "x-auth-token": localStorage.getItem("token") }
      });
      navigate('/employees');
    } catch (error) {
      console.error("Error adding employee:", error);
    }
  };

  return (
    <Container className="mt-5">
      <h2 className="text-center">Add Employee</h2>
      <Form onSubmit={handleSubmit}>
        <Form.Group className="mb-3">
          <Form.Label>Name</Form.Label>
          <Form.Control type="text" value={name} onChange={(e) => setName(e.target.value)} required />
        </Form.Group>
        <Form.Group className="mb-3">
          <Form.Label>Position</Form.Label>
          <Form.Control type="text" value={position} onChange={(e) => setPosition(e.target.value)} required />
        </Form.Group>
        <Form.Group className="mb-3">
          <Form.Label>Department</Form.Label>
          <Form.Control type="text" value={department} onChange={(e) => setDepartment(e.target.value)} required />
        </Form.Group>
        <Button variant="success" type="submit" className="w-100">Add Employee</Button>
      </Form>
    </Container>
  );
}

export default AddEmployee;
